# Module providing base models, interfaces, and enums
enum Status:
    PENDING = 0
    ACTIVE = 1
    INACTIVE = 2

interface IIdentifiable:
    def get_id(self) -> str: ...

@abstract
class BaseEntity:
    _name: str

    def __init__(self, name: str):
        self._name = name

    @virtual
    def get_display_name(self) -> str:
        return self._name

    @abstract
    def validate(self) -> bool: ...

def get_module_info() -> str:
    return "Models module loaded"

